import React from 'react';
import { useAuth } from '../contexts/AuthContext';
import { useTheme } from '../contexts';
import { useStats } from '../contexts/StatsContext';

const UserDashboard = () => {
  const { user, isDemoUser } = useAuth();
  const { theme } = useTheme();
  const { userStats } = useStats();

  const accuracyRate = userStats.totalQuestions > 0 
    ? Math.round((userStats.correctAnswers / userStats.totalQuestions) * 100)
    : 0;

  const progressPercentage = Math.min((userStats.totalQuestions / 100) * 100, 100);

  if (!user) return null;

  return (
    <div style={{
      padding: '20px',
      maxWidth: '1200px',
      margin: '0 auto',
      color: theme.text
    }}>
      <div style={{
        display: 'flex',
        alignItems: 'center',
        gap: '16px',
        marginBottom: '30px',
        padding: '20px',
        background: theme.cardBackground,
        borderRadius: '12px',
        boxShadow: `0 4px 12px ${theme.shadow}`,
        border: `1px solid ${theme.border}`
      }}>
        <img
          src={user.picture}
          alt={user.name}
          style={{
            width: '60px',
            height: '60px',
            borderRadius: '50%',
            border: `3px solid ${isDemoUser(user) ? '#ff9800' : '#4285f4'}`
          }}
        />
        <div>
          <h2 style={{ 
            margin: '0 0 8px 0', 
            fontSize: '1.5rem',
            color: theme.text 
          }}>
            Welcome back, {user.given_name}! 🎯
          </h2>
          <div style={{
            display: 'flex',
            gap: '12px',
            alignItems: 'center'
          }}>
            <span style={{
              fontSize: '0.9rem',
              padding: '4px 12px',
              borderRadius: '16px',
              background: isDemoUser(user) ? '#fff3cd' : '#d4edda',
              color: isDemoUser(user) ? '#856404' : '#155724',
            }}>
              {isDemoUser(user) ? '🎯 Demo Account' : '⭐ Premium Account'}
            </span>
            {userStats.studyStreak > 0 && (
              <span style={{
                fontSize: '0.9rem',
                padding: '4px 12px',
                borderRadius: '16px',
                background: '#ffeaa7',
                color: '#d63031',
              }}>
                🔥 {userStats.studyStreak} day streak!
              </span>
            )}
          </div>
        </div>
      </div>

      {/* Stats Grid */}
      <div style={{
        display: 'grid',
        gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))',
        gap: '20px',
        marginBottom: '30px'
      }}>
        {/* Accuracy Rate */}
        <div style={{
          padding: '20px',
          background: theme.cardBackground,
          borderRadius: '12px',
          boxShadow: `0 4px 12px ${theme.shadow}`,
          border: `1px solid ${theme.border}`,
          textAlign: 'center'
        }}>
          <div style={{
            fontSize: '2.5rem',
            fontWeight: 'bold',
            color: accuracyRate >= 80 ? '#27ae60' : accuracyRate >= 60 ? '#f39c12' : '#e74c3c',
            marginBottom: '8px'
          }}>
            {accuracyRate}%
          </div>
          <div style={{ fontSize: '1rem', color: theme.textSecondary }}>
            Overall Accuracy
          </div>
          <div style={{ fontSize: '0.8rem', color: theme.textSecondary, marginTop: '4px' }}>
            {userStats.correctAnswers} correct out of {userStats.totalQuestions}
          </div>
        </div>

        {/* Questions Answered */}
        <div style={{
          padding: '20px',
          background: theme.cardBackground,
          borderRadius: '12px',
          boxShadow: `0 4px 12px ${theme.shadow}`,
          border: `1px solid ${theme.border}`,
          textAlign: 'center'
        }}>
          <div style={{
            fontSize: '2.5rem',
            fontWeight: 'bold',
            color: '#3498db',
            marginBottom: '8px'
          }}>
            {userStats.totalQuestions}
          </div>
          <div style={{ fontSize: '1rem', color: theme.textSecondary }}>
            Questions Answered
          </div>
          <div style={{
            marginTop: '8px',
            background: '#ecf0f1',
            borderRadius: '10px',
            height: '6px',
            overflow: 'hidden'
          }}>
            <div style={{
              background: '#3498db',
              height: '100%',
              width: `${progressPercentage}%`,
              transition: 'width 0.3s ease'
            }} />
          </div>
        </div>

        {/* Study Streak */}
        <div style={{
          padding: '20px',
          background: theme.cardBackground,
          borderRadius: '12px',
          boxShadow: `0 4px 12px ${theme.shadow}`,
          border: `1px solid ${theme.border}`,
          textAlign: 'center'
        }}>
          <div style={{
            fontSize: '2.5rem',
            fontWeight: 'bold',
            color: '#e17055',
            marginBottom: '8px'
          }}>
            {userStats.studyStreak}
          </div>
          <div style={{ fontSize: '1rem', color: theme.textSecondary }}>
            Day Streak 🔥
          </div>
          <div style={{ fontSize: '0.8rem', color: theme.textSecondary, marginTop: '4px' }}>
            Keep it up!
          </div>
        </div>

        {/* Account Status */}
        <div style={{
          padding: '20px',
          background: theme.cardBackground,
          borderRadius: '12px',
          boxShadow: `0 4px 12px ${theme.shadow}`,
          border: `1px solid ${theme.border}`,
          textAlign: 'center'
        }}>
          <div style={{
            fontSize: '1.5rem',
            marginBottom: '12px'
          }}>
            {isDemoUser(user) ? '🎯' : '⭐'}
          </div>
          <div style={{ fontSize: '1rem', color: theme.textSecondary, marginBottom: '8px' }}>
            {isDemoUser(user) ? 'Demo Account' : 'Premium Account'}
          </div>
          {isDemoUser(user) && (
            <button style={{
              padding: '8px 16px',
              background: 'linear-gradient(135deg, #4285f4, #34a853)',
              color: 'white',
              border: 'none',
              borderRadius: '20px',
              fontSize: '0.8rem',
              fontWeight: '500',
              cursor: 'pointer',
              transition: 'all 0.2s ease'
            }}>
              Upgrade Now
            </button>
          )}
        </div>
      </div>

      {/* Domain Performance */}
      <div style={{
        padding: '20px',
        background: theme.cardBackground,
        borderRadius: '12px',
        boxShadow: `0 4px 12px ${theme.shadow}`,
        border: `1px solid ${theme.border}`,
        marginBottom: '20px'
      }}>
        <h3 style={{ 
          margin: '0 0 20px 0', 
          fontSize: '1.3rem',
          color: theme.text 
        }}>
          📊 Domain Performance
        </h3>
        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))',
          gap: '16px'
        }}>
          {[1, 2, 3, 4, 5, 6].map(domain => {
            const domainAccuracy = userStats.domainStrengths[`domain${domain}`] || 0;
            return (
              <div key={domain} style={{
                padding: '12px',
                background: theme.background,
                borderRadius: '8px',
                border: `1px solid ${theme.border}`
              }}>
                <div style={{ 
                  fontSize: '0.9rem', 
                  fontWeight: '600',
                  marginBottom: '8px',
                  color: theme.text
                }}>
                  Domain {domain}
                </div>
                <div style={{
                  background: '#ecf0f1',
                  borderRadius: '10px',
                  height: '8px',
                  overflow: 'hidden',
                  marginBottom: '4px'
                }}>
                  <div style={{
                    background: domainAccuracy >= 80 ? '#27ae60' : domainAccuracy >= 60 ? '#f39c12' : '#e74c3c',
                    height: '100%',
                    width: `${domainAccuracy}%`,
                    transition: 'width 0.3s ease'
                  }} />
                </div>
                <div style={{ 
                  fontSize: '0.8rem', 
                  color: theme.textSecondary,
                  textAlign: 'center'
                }}>
                  {domainAccuracy}% accuracy
                </div>
              </div>
            );
          })}
        </div>
      </div>

      {/* Quick Actions */}
      <div style={{
        padding: '20px',
        background: theme.cardBackground,
        borderRadius: '12px',
        boxShadow: `0 4px 12px ${theme.shadow}`,
        border: `1px solid ${theme.border}`
      }}>
        <h3 style={{ 
          margin: '0 0 20px 0', 
          fontSize: '1.3rem',
          color: theme.text 
        }}>
          🚀 Quick Actions
        </h3>
        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))',
          gap: '16px'
        }}>
          <button style={{
            padding: '16px',
            background: 'linear-gradient(135deg, #6c5ce7, #a29bfe)',
            color: 'white',
            border: 'none',
            borderRadius: '12px',
            fontSize: '1rem',
            fontWeight: '500',
            cursor: 'pointer',
            transition: 'all 0.2s ease',
            textAlign: 'left'
          }}>
            <div style={{ fontSize: '1.5rem', marginBottom: '8px' }}>📝</div>
            <div>Start Practice Quiz</div>
            <div style={{ fontSize: '0.8rem', opacity: 0.9 }}>Test your knowledge</div>
          </button>

          <button style={{
            padding: '16px',
            background: 'linear-gradient(135deg, #00b894, #00cec9)',
            color: 'white',
            border: 'none',
            borderRadius: '12px',
            fontSize: '1rem',
            fontWeight: '500',
            cursor: 'pointer',
            transition: 'all 0.2s ease',
            textAlign: 'left'
          }}>
            <div style={{ fontSize: '1.5rem', marginBottom: '8px' }}>🃏</div>
            <div>Review Flashcards</div>
            <div style={{ fontSize: '0.8rem', opacity: 0.9 }}>Quick review session</div>
          </button>

          <button style={{
            padding: '16px',
            background: 'linear-gradient(135deg, #fd79a8, #fdcb6e)',
            color: 'white',
            border: 'none',
            borderRadius: '12px',
            fontSize: '1rem',
            fontWeight: '500',
            cursor: 'pointer',
            transition: 'all 0.2s ease',
            textAlign: 'left'
          }}>
            <div style={{ fontSize: '1.5rem', marginBottom: '8px' }}>🎯</div>
            <div>Weak Areas</div>
            <div style={{ fontSize: '0.8rem', opacity: 0.9 }}>Focus on improvement</div>
          </button>
        </div>
      </div>
    </div>
  );
};

export default UserDashboard;
